import React from "react";
import { Button, Col, Container, Row } from "react-bootstrap";
import firebase from "./firebase";

function GetCharactersService() {
  const [characters, setCharacters] = React.useState([]);

  React.useEffect(() => {
    const fetchData = async () => {
      const db = firebase.firestore();
      const data = await db.collection("characters").get();
      setCharacters(data.docs.map((doc) => ({ id: doc.id, ...doc.data() })));
    };
    fetchData();
  }, []);

  return (
    <>
      <Row>
        {characters.map((character) => (
          <Col lg={4} key={character.id}>
            <Button
              variant="outline-warning"
              href={"/BarrysNotesOnBarovia/#/Character/" + character.id}
            >
              <Container>
                <img
                  className="character-thumbnail"
                  src={character.pictureURL}
                  alt="pic"
                />
                <h3>Name: {character.name}</h3>
              </Container>
            </Button>
          </Col>
        ))}
      </Row>
    </>
  );
}

export default GetCharactersService;
