import React from "react";
import { AbilityInput } from "../components/AbilityInput";
import { SpellInput } from "../components/SpellInput";
import { Button, Col, Container, Row, Tabs, Tab } from "react-bootstrap";

import { NameInput } from "../components/NameInput";
import firebase from "./firebase";

const SingleCharacterUpdate = ({ docId }) => {
  const [character, setCharacter] = React.useState("");
  const [key, setKey] = React.useState("basicInfo");

  React.useEffect(() => {
    if (character !== "") {
      return;
    }
    firebase
      .firestore()
      .collection("characters")
      .doc(docId)
      .get()
      .then((snapshot) => {
        console.log(snapshot.data());
        //character = { ...snapshot.data() };
        setCharacter(snapshot.data());
      })
      .catch((e) => console.log(e));
  });

  return (
    <div className="single-character">
      +
      <Tabs
        id="controlled-tab-example"
        activeKey={key}
        onSelect={(k) => setKey(k)}
      >
        <Tab
          eventKey="basicInfo"
          title="Update Basic Info"
          tabClassName="tab-name"
        >
          <NameInput
            character={character}
            docId={docId}
            charName={character.name}
          />
        </Tab>
        <Tab
          eventKey="abilitiesView"
          title="Add a new Ability"
          tabClassName="tab-name"
        >
          <AbilityInput docId={docId} />
        </Tab>
        <Tab
          eventKey="spellsView"
          title="Add a new Spell"
          tabClassName="tab-name"
        >
          <SpellInput docId={docId} />
        </Tab>
      </Tabs>
    </div>
  );
};

export default SingleCharacterUpdate;
