import React from "react";
import { Button, Col, Row } from "react-bootstrap";
import firebase from "../controller/firebase";

export const SpellInput = ({ docId }) => {
  const [newName, setNewName] = React.useState();
  const [newLevel, setNewLevel] = React.useState();
  const [newCastingTime, setNewCastingTime] = React.useState();
  const [newRange, setNewRange] = React.useState();
  const [newDuration, setNewDuration] = React.useState();
  const [newSchool, setNewSchool] = React.useState();
  const [newAttackSave, setNewAttackSave] = React.useState();
  const [newDamage, setNewDamage] = React.useState();
  const [newDesc, setNewDesc] = React.useState();

  const onCreate = async (e) => {
    e.preventDefault();
    const db = firebase.firestore();
    await db.collection("characters/" + docId + "/spells").add({
      name: newName,
      level: newLevel,
      castingTime: newCastingTime,
      range: newRange,
      duration: newDuration,
      school: newSchool,
      attackSave: newAttackSave,
      damage: newDamage,
      description: newDesc,
    });
    setNewDesc("");
    setNewLevel("");
    setNewCastingTime("");
    setNewRange("");
    setNewDuration("");
    setNewSchool("");
    setNewAttackSave("");
    setNewName("");
    setNewDamage("");
  };

  return (
    <form onSubmit={onCreate}>
      <div className="update-card-border">
        <div className="update-card">
          <Row>
            <Col>
              <h1>Add a Spell</h1>
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Name</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                required
              />
            </Col>
            <Col>
              <h2>Level</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newLevel}
                onChange={(e) => setNewLevel(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Casting Time</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newCastingTime}
                onChange={(e) => setNewCastingTime(e.target.value)}
                required
              />
            </Col>
            <Col>
              <h2>Range/Area</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newRange}
                onChange={(e) => setNewRange(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Duration</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newDuration}
                onChange={(e) => setNewDuration(e.target.value)}
                required
              />
            </Col>
            <Col>
              <h2>School</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newSchool}
                onChange={(e) => setNewSchool(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Attack/Save</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newAttackSave}
                onChange={(e) => setNewAttackSave(e.target.value)}
                required
              />
            </Col>
            <Col>
              <h2>Damage/Effect</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newDamage}
                onChange={(e) => setNewDamage(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <h2>Description</h2>
            <textarea
              className="update-card-input text-area"
              rows={5}
              cols={5}
              value={newDesc}
              onChange={(e) => setNewDesc(e.target.value)}
              required
            />
          </Row>
          <Button
            classname="update-card-button"
            type="submit"
            variant="warning"
            size="lg"
            block
          >
            Add Spell
          </Button>
        </div>
      </div>
    </form>
  );
};
