import React, { Component } from "react";
import GetSingleCharacterService from "../controller/getSingleCharacterService";

class SingleCharacter extends Component {
  state = {
    docId: this.props.match.params.id,
    toUpdate: false,
  };

  render() {
    return (
      <div className="App">
        <GetSingleCharacterService docId={this.state.docId} />
      </div>
    );
  }
}

export default SingleCharacter;

